#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=1e6+5,MOD=998244353;
ll a[MAXN],l[MAXN],r[MAXN],sum[45],n,ans=0;
int main(void){
	n=read();
	for(int i=1;i<=n;++i)
    {
		a[i]=read();
	}
	a[0]=a[n+1]=1,l[0]=r[n+1]=1;
	for(int i=1;i<=n;++i)
    {
		sum[a[i]]=(sum[a[i]]+l[i-1])%MOD;
		l[i]=sum[a[i]];
	}
	memset(sum,0,sizeof sum);
	for(int i=n;i>=1;--i)
    {
		sum[a[i]]=(sum[a[i]]+r[i+1])%MOD;
		r[i]=sum[a[i]];
	}
	for(int i=1;i<=40;++i)
    {
		int cnt=0,res=0;
		for(int j=1;j<=n;++j)
        {
			if(a[j]==i)
            {
				res=((res+l[j-1])%MOD*a[j])%MOD;
				cnt=(cnt+(r[j+1]*res%MOD))%MOD;
			}
			else res=res*a[j]%MOD;
		}
		ans=(ans+cnt)%MOD;
	}
	write(ans);
	return false;
}
